    t:'Wiedweg 08. Etappe Niederbreitbach \u2013 Irlich (Neuwied)',
    km:'18,7',
    sw:'mittel',
    d:'Wiedschleife B\u00fcrder, Burg Altwied, Wiedm\u00fcndung Rhein',
    url:'https://www.westerwald.info/d/wiedweg-08-etappe-niederbreitbach-irlich/',
